namespace InventoryApp.Models;

public class EquipmentItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime LastInspected { get; set; }
}

using InventoryApp.Models;

namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a data-access delay
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new() { Id = 1, Name = "Forklift A",        Location = "Warehouse 1", LastInspected = new DateTime(2026, 3, 15) },
            new() { Id = 2, Name = "Conveyor Belt B",   Location = "Warehouse 2", LastInspected = new DateTime(2026, 4, 20) },
            new() { Id = 3, Name = "Pallet Jack C",     Location = "Dock 3",      LastInspected = new DateTime(2026, 1, 10) },
            new() { Id = 4, Name = "Crane D",           Location = "Yard",        LastInspected = new DateTime(2025, 12, 5) },
            new() { Id = 5, Name = "Compressor E",      Location = "Plant Room",  LastInspected = new DateTime(2026, 5, 1) },
            new() { Id = 6, Name = "Drill Press F",     Location = "Workshop",    LastInspected = new DateTime(2026, 2, 28) },
            new() { Id = 7, Name = "Welding Rig G",     Location = "Bay 4",       LastInspected = new DateTime(2026, 4, 12) },
            new() { Id = 8, Name = "Generator H",       Location = "Utility Shed",LastInspected = new DateTime(2025, 11, 22) },
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@inject EquipmentService EquipmentSvc
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private const string PersistenceKey = "inventory-items";
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _subscription;

    protected override async Task OnInitializedAsync()
    {
        // Register callback so prerender can persist the data for the interactive phase
        _subscription = ApplicationState.RegisterOnPersisting(PersistData);

        // If the interactive render can restore persisted data, skip the service call
        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>(PersistenceKey, out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentSvc.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson(PersistenceKey, _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

